-- ═══ VittaSys — INSERT massa real de clientes ativos ═══
-- Nome = nome do paciente (bebê/criança)
-- data_nascimento = nascimento do paciente
-- responsavel_nome = responsável financeiro (mãe/pai)
-- cpf = CPF do responsável
-- paciente_nome + paciente_nascimento = cópia dos dados do paciente para os novos campos

INSERT INTO clientes (
    nome,
    data_nascimento,
    sexo,
    cpf,
    telefone,
    email,
    tipo_paciente,
    tipo_cliente,
    responsavel_nome,
    responsavel_parentesco,
    responsavel_cpf,
    responsavel_telefone,
    paciente_nome,
    paciente_nascimento,
    vendedor_id,
    vacinador_id,
    status,
    observacoes,
    observacoes_clinicas,
    criado_em,
    atualizado_em
)
